/**
 * @fileoverview Shared content setter — resolves string HTML, DOM Element,
 * or razyui Elements into a container.
 *
 * Usage:
 *   import { setContent } from '../shared/setContent.js';
 *
 *   // String HTML
 *   setContent($el, '<b>Hello</b>');
 *
 *   // DOM Element
 *   setContent($el, document.createElement('div'));
 *
 *   // razyui Elements
 *   setContent($el, razyui.el('div', { className: 'foo' }));
 *
 * @module shared/setContent
 */

/**
 * Apply rendered content to a razyui Elements wrapper.
 *
 * Supports:
 *   - String HTML  → sets via `.html()`
 *   - DOM Node     → clears and appends
 *   - razyui Elements (extends Array, `[0]` is a Node) → clears and appends
 *
 * @param {Elements} $el      razyui Elements wrapper (target)
 * @param {string|Node|Elements} content  The content to apply
 */
export function setContent($el, content) {
    if (content instanceof Node) {
        $el.html('').append(content);
    } else if (content != null && typeof content === 'object' && content[0] instanceof Node) {
        // razyui Elements instance (extends Array)
        $el.html('').append(content);
    } else {
        $el.html(content);
    }
}
